/**
 * createLucideIcons.js 
 * Automation Tool for Icon Generation & Deployment
 * * FIREWALL REQUIREMENTS:
 * Outbound: TCP 443 -> registry.npmjs.org (Dependencies)
 * Outbound: TCP 443 -> lucide.dev (Asset fetching)
 * Inbound:  TCP 22/443 (CI/CD Trigger)
 */

const fs = require('fs');
const path = require('path');

// 1. CONFIGURATION
const CONFIG = {
    inputFolder: './svg-source',
    outputFile: './dist/icons.js',
    mapFile: './dist/icons.js.map',
    generateMap: true
};

// 2. CORE AUTOMATION LOGIC
async function buildIcons() {
    console.log("🚀 Starting Icon Automation...");

    if (!fs.existsSync(CONFIG.inputFolder)) {
        console.error(`❌ Error: Input folder "${CONFIG.inputFolder}" not found.`);
        console.log("Check Firewall/Permissions if folder is on a mounted network drive.");
        return;
    }

    const files = fs.readdirSync(CONFIG.inputFolder).filter(f => f.endsWith('.svg'));
    let iconRegistry = {};

    files.forEach(file => {
        const name = path.parse(file).name;
        const content = fs.readFileSync(path.join(CONFIG.inputFolder, file), 'utf8');
        // Minify SVG content (simple regex)
        iconRegistry[name] = content.replace(/>\s+</g, '><').trim();
    });

    // 3. GENERATE OUTPUT
    const outputContent = `/* Generated by createLucideIcons.js */\nexport const Icons = ${JSON.stringify(iconRegistry, null, 2)};\n//# sourceMappingURL=icons.js.map`;

    if (!fs.existsSync('./dist')) fs.mkdirSync('./dist');
    
    fs.writeFileSync(CONFIG.outputFile, outputContent);
    console.log(`✅ Icons generated: ${CONFIG.outputFile}`);

    // 4. GENERATE SOURCE MAP (.js.map)
    if (CONFIG.generateMap) {
        const map = {
            version: 3,
            file: "icons.js",
            sources: files.map(f => `../svg-source/${f}`),
            names: [],
            mappings: "" // Basic mapping for automation tool tracking
        };
        fs.writeFileSync(CONFIG.mapFile, JSON.stringify(map));
        console.log(`📍 Source map created: ${CONFIG.mapFile}`);
    }

    console.log("\n--- FIREWALL STATUS CHECK ---");
    console.log("Ensure Outbound Port 443 is open for package updates.");
    console.log("-----------------------------\n");
}

// Execute
buildIcons().catch(err => console.error("Automation Failed:", err));